  1	import * as React from 'react';
  2	import { useODFSystemFlagsSelector } from '@odf/core/redux';
  3	import { useGetClusterDetails } from '@odf/core/redux/utils';
  4	import { DataUnavailableError } from '@odf/shared/generic';
  5	import { FieldLevelHelp } from '@odf/shared/generic/FieldLevelHelp';
  6	import {
  7	  useCustomPrometheusPoll,
  8	  usePrometheusBasePath,
  9	} from '@odf/shared/hooks/custom-prometheus-poll';
 10	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
 11	import { PrometheusResponse } from '@openshift-console/dynamic-plugin-sdk';
 12	import * as _ from 'lodash-es';
 13	import { Card, CardBody, CardHeader, CardTitle } from '@patternfly/react-core';
 14	import { ResourceProvidersBody } from './resource-providers-card-body';
 15	import {
 16	  ResourceProvidersItem,
 17	  ProviderType,
 18	} from './resource-providers-card-item';
 19	import './resource-providers-card.scss';
 20	
 21	const RESOURCE_PROVIDERS_QUERY = {
 22	  PROVIDERS_TYPES: ' NooBaa_cloud_types',
 23	  UNHEALTHY_PROVIDERS_TYPES: 'NooBaa_unhealthy_cloud_types',
 24	};
 25	
 26	const getProviderType = (provider: ProviderPrometheusData): string =>
 27	  _.get(provider, 'metric.type', null);
 28	const getProviderCount = (provider: ProviderPrometheusData): number =>
 29	  Number(_.get(provider, 'value[1]', null));
 30	
 31	const filterProviders = (allProviders: ProviderType): string[] => {
 32	  return _.keys(allProviders).filter((provider) => allProviders[provider] > 0);
 33	};
 34	
 35	const createProvidersList = (data: PrometheusResponse): ProviderType => {
 36	  const providers = _.get(data, 'data.result', null);
 37	  const providersList: ProviderType = {};
 38	  if (_.isNil(providers)) return {};
 39	  providers.forEach((provider) => {
 40	    providersList[getProviderType(provider)] = getProviderCount(provider);
 41	  });
 42	  return providersList;
 43	};
 44	
 45	const MCGResourceProvidersBody: React.FC = () => {
 46	  const [providersTypesQueryResult, providersTypesQueryResultError] =
 47	    useCustomPrometheusPoll({
 48	      query: RESOURCE_PROVIDERS_QUERY.PROVIDERS_TYPES,
 49	      endpoint: 'api/v1/query' as any,
 50	      basePath: usePrometheusBasePath(),
 51	    });
 52	  const [
 53	    unhealthyProvidersTypesQueryResult,
 54	    unhealthyProvidersTypesQueryResultError,
 55	  ] = useCustomPrometheusPoll({
 56	    query: RESOURCE_PROVIDERS_QUERY.UNHEALTHY_PROVIDERS_TYPES,
 57	    endpoint: 'api/v1/query' as any,
 58	    basePath: usePrometheusBasePath(),
 59	  });
 60	
 61	  const error =
 62	    !!providersTypesQueryResultError ||
 63	    !!unhealthyProvidersTypesQueryResultError;
 64	
 65	  const allProviders = createProvidersList(providersTypesQueryResult);
 66	  const unhealthyProviders = createProvidersList(
 67	    unhealthyProvidersTypesQueryResult
 68	  );
 69	
 70	  const providerTypes = filterProviders(allProviders);
 71	
 72	  return (
 73	    <ResourceProvidersBody
 74	      isLoading={
 75	        !error &&
 76	        !(providersTypesQueryResult && unhealthyProvidersTypesQueryResult)
 77	      }
 78	      hasProviders={!_.isEmpty(allProviders)}
 79	      error={error}
 80	    >
 81	      {providerTypes.map((provider) => (
 82	        <ResourceProvidersItem
 83	          count={allProviders[provider]}
 84	          key={provider}
 85	          title={provider}
 86	          unhealthyProviders={unhealthyProviders}
 87	        />
 88	      ))}
 89	    </ResourceProvidersBody>
 90	  );
 91	};
 92	
 93	const ResourceProviders: React.FC<{}> = () => {
 94	  const { t } = useCustomTranslation();
 95	
 96	  const { clusterNamespace: clusterNs } = useGetClusterDetails();
 97	  const { systemFlags } = useODFSystemFlagsSelector();
 98	  const hasMCG = systemFlags[clusterNs]?.isNoobaaAvailable;
 99	
100	  return (
101	    <Card>
102	      <CardHeader>
103	        <CardTitle>
104	          {t('Resource providers')}
105	          <FieldLevelHelp>
106	            {t(
107	              "A list of all Multicloud Object Gateway resources that are currently in use. Those resources are used to store data according to the buckets' policies and can be a cloud-based resource or a bare metal resource."
108	            )}
109	          </FieldLevelHelp>
110	        </CardTitle>
111	      </CardHeader>
112	      <CardBody>
113	        {hasMCG ? <MCGResourceProvidersBody /> : <DataUnavailableError />}
114	      </CardBody>
115	    </Card>
116	  );
117	};
118	
119	type ProviderPrometheusData = {
120	  metric: { [key: string]: any };
121	  value?: [number, string | number];
122	};
123	
124	export const ResourceProvidersCard = ResourceProviders;

